try {
  const item = $input.first();
  const output = (item && item.json && item.json.output) ? String(item.json.output) : '';

  if (!output) return [{ json: { output: 'ERROR: AI Agent returned no output' } }];

  // Find [CHARTS_JSON] tag
  const tagIdx = output.search(/\[CHARTS_JSON\]/);
  if (tagIdx === -1) return [{ json: { output } }];

  // Get text after tag
  const after = output.slice(tagIdx + 13).trimStart();

  // Extract JSON array via bracket-counting
  const start = after.indexOf('[');
  if (start === -1) return [{ json: { output } }];

  let depth = 0, end = -1;
  for (let i = start; i < after.length; i++) {
    if (after[i] === '[') depth++;
    else if (after[i] === ']') { depth--; if (depth === 0) { end = i; break; } }
  }

  const chartsJson = end !== -1 ? after.slice(start, end + 1) : after.slice(start);

  // Get analysis after [/CHARTS_JSON]
  const closeIdx = output.indexOf('[/CHARTS_JSON]');
  const analysis = closeIdx !== -1 ? output.slice(closeIdx + 14).trim() : '';

  return [{ json: { output: chartsJson + '\n---ANALYSIS---\n' + analysis } }];
} catch(e) {
  return [{ json: { output: 'ERROR: ' + e.message } }];
}
